/**
 * check-guidelines.js (Object Request List)
 *
 * ============================================================================
 * IMPORTANT: ONLY FOR CLAUDE-GENERATED FILES
 * ============================================================================
 *
 * This validator should ONLY be run on files that were NEWLY GENERATED BY CLAUDE.
 *
 * Purpose:
 *   - Verify that Claude-generated code follows all ObjectRequestList guidelines
 *   - Catch guideline violations before they enter the codebase
 *   - Ensure consistent patterns in AI-generated list request implementations
 *
 * When to use:
 *   - After Claude generates code using ObjectRequestList
 *   - After Claude implements filtering, sorting, or pagination
 *   - After Claude modifies list request configurations
 *
 * When NOT to use:
 *   - On existing legacy code
 *   - On third-party or external code
 *
 * ============================================================================
 * AUTO-FIX WORKFLOW
 * ============================================================================
 *
 * This script will automatically:
 * 1. Scan for guideline violations
 * 2. Run fix-guidelines.js on files with errors
 * 3. Re-validate after fixing
 *
 * ============================================================================
 *
 * Validates correct usage of ObjectRequestList patterns.
 */

const fs = require('fs');
const path = require('path');
const { execSync } = require('child_process');

const SRC_DIR = path.resolve(process.cwd(), 'src');
const FIX_SCRIPT = path.resolve(__dirname, 'fix-guidelines.js');

const filesWithErrors = new Set();

function error(msg, file) {
  console.error(`❌ OBJECT REQUEST LIST ERROR: ${msg}`);
  if (file) filesWithErrors.add(file);
}

function check(condition, msg, file) {
  if (!condition) error(msg, file);
}

function scan(dir) {
  if (!fs.existsSync(dir)) return [];
  return fs.readdirSync(dir, { withFileTypes: true })
    .flatMap(e =>
      e.isDirectory() ? scan(path.join(dir, e.name)) :
      e.name.endsWith('.ts') ? [path.join(dir, e.name)] : []
    );
}

function runValidation() {
  filesWithErrors.clear();

  scan(SRC_DIR).forEach(file => {
    const content = fs.readFileSync(file, 'utf-8');

    if (content.includes('ObjectRequestList')) {

      check(
        content.includes('FilterCriteria.create'),
        `${file}: Filters must be created using FilterCriteria.create(). See object-request-list.md`,
        file
      );

      check(
        !content.includes('DtoId'),
        `${file}: Do not filter using DtoId or Id fields. Use relationship names. See object-request-list.md`,
        file
      );

      check(
        content.includes('new Sorting'),
        `${file}: Sorting must use new Sorting(). See object-request-list.md`,
        file
      );

      check(
        content.includes('PagingDto') || !content.includes('list('),
        `${file}: User-facing list requests must use PagingDto. See object-request-list.md`,
        file
      );

      check(
        !content.includes('HttpClient'),
        `${file}: Do not manually use HttpClient for entity lists. Use ObjectRequestList. See object-request-list.md`,
        file
      );
    }
  });

  return filesWithErrors.size;
}

// Initial validation
console.log('🔍 Running Object Request List guideline validation...\n');
let errorCount = runValidation();

if (errorCount > 0) {
  console.log(`\n🔧 Found ${errorCount} file(s) with errors. Running auto-fix...\n`);

  // Run fix-guidelines.js for each file with errors
  for (const file of filesWithErrors) {
    console.log(`\n📄 Fixing: ${file}`);
    try {
      execSync(`node "${FIX_SCRIPT}" "${file}"`, { stdio: 'inherit' });
    } catch (e) {
      console.error(`Failed to fix ${file}: ${e.message}`);
    }
  }

  // Re-validate after fixing
  console.log('\n🔍 Re-validating after fixes...\n');
  errorCount = runValidation();

  if (errorCount > 0) {
    console.log(`\n⚠️  ${errorCount} file(s) still have errors after auto-fix.`);
    console.log('Manual intervention may be required for the remaining issues.');
  }
}

if (errorCount === 0) {
  console.log('\n✅ Object Request List guideline check completed - all files pass!');
} else {
  console.log('\n⚠️  Object Request List guideline check completed with warnings.');
  process.exit(1);
}
